* {
  box-sizing: border-box;
  font-family: "Poppins", sans-serif;
}

body {
  background-color: transparent;
  margin: 0;
  padding: 10px;
}

.offers-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: 20px;
}

.offer-card {
  background: white;
  border-radius: 12px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  border: 1px solid #eef2f6;
  transition: all 0.2s;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  position: relative;
}

.offer-card:hover {
  border-color: #82DB35;
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(130, 219, 53, 0.15);
}

.card-header {
  padding: 16px;
  border-bottom: 1px solid #f1f5f9;
  display: flex;
  align-items: center;
}

.logo-container {
  width: 44px;
  height: 44px;
  background: white;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 4px;
  border: 1px solid #f1f5f9;
  margin-right: 12px;
  flex-shrink: 0;
}

.logo-img {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
}

.logo-fallback {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 100%;
  height: 100%;
  background: #e2e8f0;
  color: #475569;
  font-weight: 800;
  font-size: 1.1rem;
  border-radius: 4px;
  letter-spacing: 0.5px;
}

.header-text {
  flex-grow: 1;
}

.prod-name {
  font-weight: 700;
  color: #1e293b;
  margin: 0;
  font-size: 0.95rem;
  line-height: 1.2;
}

.carrier {
  color: #64748b;
  font-size: 0.75rem;
}

.badge-pf {
  background: #f1f5f9;
  color: #475569;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 600;
}

.card-body {
  padding: 16px;
  flex-grow: 1;
}

.main-price {
  text-align: center;
  margin-bottom: 16px;
}

.price-val {
  font-size: 1.8rem;
  font-weight: 700;
  color: #82DB35;
}

.price-lbl {
  font-size: 0.75rem;
  color: #94a3b8;
  display: block;
}

.stats-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  background: #f8fafc;
  padding: 12px;
  border-radius: 8px;
}

.stat-label {
  font-size: 0.7rem;
  color: #64748b;
  display: block;
}

.stat-value {
  font-weight: 600;
  color: #334155;
  font-size: 0.85rem;
}

.guarantees-bar {
  display: flex;
  gap: 6px;
  margin-top: 12px;
  flex-wrap: wrap;
}

.g-item {
  font-size: 0.7rem;
  background: #ecfdf5;
  color: #065f46;
  padding: 2px 6px;
  border-radius: 4px;
}

.schedule-box {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s ease-out;
  background: #fdfdfd;
}

.schedule-box.open {
  max-height: 250px;
  overflow-y: auto;
  padding: 12px;
  border-top: 1px solid #f1f5f9;
}

.schedule-table {
  width: 100%;
  font-size: 0.75rem;
  border-collapse: collapse;
}

.schedule-table th {
  color: #94a3b8;
  text-align: left;
  padding-bottom: 4px;
}

.schedule-table td {
  padding: 4px 0;
  border-bottom: 1px solid #f8fafc;
}

.card-footer {
  padding: 12px;
  display: flex;
  gap: 8px;
  background: #fcfcfc;
}

.btn {
  flex: 1;
  padding: 8px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.8rem;
  font-weight: 600;
  border: none;
  transition: filter 0.2s;
}

.btn-sec {
  background: #f1f5f9;
  color: #475569;
}

.btn-pri {
  background: #82DB35;
  color: white;
}

.btn:hover {
  filter: brightness(0.95);
}

.debug-view {
  font-size: 10px;
  background: #eee;
  padding: 10px;
  overflow: auto;
  max-height: 200px;
  text-align: left;
}

