const { useState, useEffect } = React;

const Offer = ({ data }) => {
  const [open, setOpen] = useState(false);
  const fmt = (num) => (typeof num === 'number') ? num.toLocaleString('fr-FR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '0,00';
  const fmtInt = (num) => (typeof num === 'number') ? Math.round(num).toLocaleString('fr-FR') : '0';

  const getLogoUrl = (offer) => {
    let slug = "default";
    const pr = offer.porteur_risque?.toLowerCase() || "";
    const pf = offer.plateforme?.toLowerCase();

    if (pr.includes("generali")) slug = "generali";
    else if (pr.includes("malakoff") || pr.includes("premium")) slug = "malakoff";
    else if (pr.includes("axeria")) slug = "axeria";
    else if (pr.includes("prevoir")) slug = "prevoir";
    else if (pr.includes("swiss")) slug = "swisslife";
    else if (pr.includes("allianz")) slug = "allianz";
    else if (pr.includes("axa")) slug = "axa";
    else if (pr.includes("macif")) slug = "macif";
    else if (pr.includes("april")) slug = "april";
    else if (pr.includes("assurea")) slug = "assurea";
    else if (pr.includes("mgen")) slug = "mgen";
    else if (pf === "ugip") slug = "ugip";
    else if (pf === "utwin") slug = "utwin";

    return `https://s3.eu-west-3.amazonaws.com/ideel.images/logos/${slug}.png`;
  };

  const getInitials = (offer) => {
    if (offer.porteur_risque && offer.porteur_risque !== "Non spécifié") {
      return offer.porteur_risque.substring(0, 2).toUpperCase();
    }
    return offer.plateforme ? offer.plateforme.substring(0, 2).toUpperCase() : "ID";
  };

  return (
    <div className="offer-card">
      <div className="card-header">
        <div className="logo-container">
          <img 
            src={getLogoUrl(data)} 
            alt={getInitials(data)} 
            className="logo-img" 
            onError={(e) => {
              e.target.style.display = 'none';
              e.target.nextSibling.style.display = 'flex';
            }}
          />
          <div className="logo-fallback" style={{display: 'none'}}>
            {getInitials(data)}
          </div>
        </div>
        <div className="header-text">
          <p className="prod-name">{data.id_produit}</p>
          <span className="carrier">{data.porteur_risque === "Non spécifié" ? data.plateforme : data.porteur_risque}</span>
        </div>
        <span className="badge-pf">{data.plateforme}</span>
      </div>

      <div className="card-body">
        <div className="main-price">
          <span className="price-val">{fmt(data.mensualite_moyenne_euro)}€</span>
          <span className="price-lbl">Mensualité moyenne</span>
        </div>

        <div className="stats-grid">
          <div><span className="stat-label">TAEA</span><span className="stat-value">{typeof data.taea_pourcentage === 'number' ? data.taea_pourcentage.toFixed(3) : '0'}%</span></div>
          <div><span className="stat-label">Type</span><span className="stat-value">{data.type_tarification || 'N/A'}</span></div>
          <div><span className="stat-label">Coût Total</span><span className="stat-value">{fmtInt(data.cout_total_euro)}€</span></div>
          <div><span className="stat-label">Coût 8 ans</span><span className="stat-value">{fmtInt(data.cout_8_ans_euro)}€</span></div>
        </div>

        <div className="guarantees-bar">
          <span className="g-item">DC {data.garanties?.quotite_deces || 0}%</span>
          <span className="g-item">ITT {data.garanties?.quotite_itt || 0}%</span>
          <span className="g-item">Franchise {data.garanties?.franchise_jours || 0}j</span>
        </div>
      </div>

      <div className={`schedule-box ${open ? 'open' : ''}`}>
        <table className="schedule-table">
          <thead><tr><th>Mois</th><th>Montant</th></tr></thead>
          <tbody>{data.echeancier?.map(m => (<tr key={m.mois}><td>Mois {m.mois}</td><td><strong>{fmt(m.montant)}€</strong></td></tr>))}</tbody>
        </table>
      </div>

      <div className="card-footer">
        <button className="btn btn-sec" onClick={() => setOpen(!open)}>{open ? 'Fermer' : 'Échéancier'}</button>
        <button className="btn btn-pri" onClick={() => appsmith.triggerEvent("onSelectOffer", { offer: data })}>Sélectionner</button>
      </div>
    </div>
  );
}

const Main = () => {
  const [list, setList] = useState([]);

  useEffect(() => {
    const processData = (model) => {
      const m = model || appsmith.model;
      if (!m) return;

      let rawList = m.offers || m;
      if (rawList.data) rawList = rawList.data;
      if (rawList.searchLoanPotentialOffers) rawList = rawList.searchLoanPotentialOffers;
      if (!Array.isArray(rawList) && rawList.offers) rawList = rawList.offers;

      setList(Array.isArray(rawList) ? rawList : []);
    };

    processData();
    const unsubscribe = appsmith.onModelChange((newModel) => processData(newModel));

    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  return (
    <div className="offers-grid">
      {list.length > 0 ? (
        list.map((o, i) => (<Offer key={i} data={o} />))
      ) : (
        <div style={{gridColumn: '1/-1', textAlign: 'center', padding: '40px', color: '#94a3b8'}}>
           <p>En attente des données...</p>
        </div>
      )}
    </div>
  );
}

appsmith.onReady(() => { ReactDOM.render(<Main />, document.getElementById('root')); });
